import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  getAllSupportsApi,
  getMySupportsApi,
  updateSupportStatusApi
} from '../api/apiServices';
import SupportRequestDetailModal from '../components/SupportRequestDetailModal';
import './RequestList.css';

const RequestList = () => {
  const navigate = useNavigate();

  const [activeTab, setActiveTab] = useState('ALL');
  const [statusFilter, setStatusFilter] = useState('ALL');
  const [requests, setRequests] = useState([]);
  const [myRequests, setMyRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedReq, setSelectedReq] = useState(null);
  const [error, setError] = useState('');

  const currentUser = JSON.parse(localStorage.getItem('user') || '{}');

  const getStatusLabel = (status) => {
    switch (status) {
      case 'PENDING':
        return 'Chờ xử lý';
      case 'ASSIGNED':
        return 'Đã phân công';
      case 'IN_PROGRESS':
        return 'Đang hỗ trợ';
      case 'RESOLVED':
        return 'Đã được giúp đỡ';
      case 'CANCELLED':
        return 'Đã hủy';
      default:
        return status || 'Không xác định';
    }
  };

  const getRequestTypeLabel = (type) => {
    switch (type) {
      case 'RESCUE':
        return 'Cứu hộ';
      case 'FOOD':
        return 'Lương thực';
      case 'MEDICAL':
        return 'Y tế';
      case 'SHELTER':
        return 'Nơi trú ẩn';
      case 'SUPPLIES':
        return 'Nhu yếu phẩm';
      default:
        return type || 'Không xác định';
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    setError('');

    try {
      const [allRes, myRes] = await Promise.all([
        getAllSupportsApi().catch(() => ({ data: [] })),
        getMySupportsApi().catch(() => ({ data: [] }))
      ]);

      setRequests(Array.isArray(allRes.data) ? allRes.data : []);
      setMyRequests(Array.isArray(myRes.data) ? myRes.data : []);
    } catch (err) {
      console.error(err);
      setError('Không thể tải danh sách yêu cầu hỗ trợ.');
    } finally {
      setLoading(false);
    }
  };

  const filtered = useMemo(() => {
    let list = [];

    if (activeTab === 'ALL') {
      list = [...requests];
    } else if (activeTab === 'MINE') {
      list = [...myRequests];
    } else {
      const myIds = new Set(myRequests.map((r) => r.id));
      list = requests.filter((r) => !myIds.has(r.id));
    }

    if (statusFilter !== 'ALL') {
      list = list.filter((r) => r.status === statusFilter);
    }

    return list.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  }, [activeTab, statusFilter, requests, myRequests]);

  const handleUpdateStatus = async (id, newStatus) => {
    try {
      await updateSupportStatusApi(id, newStatus);
      await fetchData();
      setSelectedReq(null);
    } catch (err) {
      console.error(err);
      alert('Cập nhật trạng thái thất bại');
    }
  };

  const handleOpenMap = (req) => {
    navigate('/', {
      state: {
        routeToDest: {
          lat: req.latitude,
          lng: req.longitude
        }
      }
    });
  };

  const isMyRequest = (requestId) => myRequests.some((item) => item.id === requestId);

  return (
    <div className="request-list-page container">
      <div className="request-list-header">
        <div>
          <h2>Danh sách yêu cầu</h2>
          <p>Theo dõi các yêu cầu hỗ trợ của bạn và cộng đồng.</p>
        </div>
      </div>

      <div className="request-list-toolbar">
        <div className="request-tabs">
          <button
            className={`toolbar-btn ${activeTab === 'ALL' ? 'active' : ''}`}
            onClick={() => setActiveTab('ALL')}
          >
            Tất cả
          </button>

          <button
            className={`toolbar-btn ${activeTab === 'MINE' ? 'active' : ''}`}
            onClick={() => setActiveTab('MINE')}
          >
            Yêu cầu của tôi
          </button>

          <button
            className={`toolbar-btn ${activeTab === 'OTHERS' ? 'active' : ''}`}
            onClick={() => setActiveTab('OTHERS')}
          >
            Người khác
          </button>
        </div>

        <select
          className="status-select"
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
        >
          <option value="ALL">Mọi trạng thái</option>
          <option value="PENDING">Chờ xử lý</option>
          <option value="ASSIGNED">Đã phân công</option>
          <option value="IN_PROGRESS">Đang hỗ trợ</option>
          <option value="RESOLVED">Đã được giúp đỡ</option>
          <option value="CANCELLED">Đã hủy</option>
        </select>
      </div>

      {loading ? (
        <div className="request-state-card">
          <div className="request-state-icon">⏳</div>
          <h3>Đang tải dữ liệu</h3>
          <p>Vui lòng chờ một chút để hệ thống lấy danh sách yêu cầu hỗ trợ.</p>
        </div>
      ) : error ? (
        <div className="request-state-card error">
          <div className="request-state-icon">⚠️</div>
          <h3>Đã xảy ra lỗi</h3>
          <p>{error}</p>
          <button className="toolbar-btn active" onClick={fetchData}>
            Tải lại
          </button>
        </div>
      ) : filtered.length === 0 ? (
        <div className="request-state-card">
          <div className="request-state-icon">📭</div>
          <h3>Không có yêu cầu phù hợp</h3>
          <p>Hiện chưa có dữ liệu khớp với bộ lọc mà bạn đang chọn.</p>
        </div>
      ) : (
        <div className="request-grid">
          {filtered.map((r) => {
            const mine = isMyRequest(r.id);

            return (
              <div
                key={r.id}
                className="request-card"
                onClick={() => setSelectedReq({ ...r, isMine: mine })}
              >
                <div className="request-card-top">
                  <div className="request-card-type">
                    {getRequestTypeLabel(r.requestType)}
                  </div>

                  <span className={`status-badge ${String(r.status || '').toLowerCase()}`}>
                    {getStatusLabel(r.status)}
                  </span>
                </div>

                <p className="request-card-description">
                  {r.description || 'Không có mô tả'}
                </p>

                <div className="request-card-meta">
                  <span>👥 {r.numberOfPeople || 0} người</span>
                  <span>
                    📅{' '}
                    {r.createdAt
                      ? new Date(r.createdAt).toLocaleDateString('vi-VN')
                      : 'Không rõ'}
                  </span>
                </div>

                <div className="request-card-address">
                  <span className="address-label">Địa chỉ</span>
                  <span className="address-value">
                    {r.address || 'Chưa xác định địa chỉ'}
                  </span>
                </div>

                <div className="request-card-footer">
                  {mine ? (
                    <span className="mine-label">YÊU CẦU CỦA BẠN</span>
                  ) : (
                    <span className="other-label">YÊU CẦU CỘNG ĐỒNG</span>
                  )}

                  <button
                    type="button"
                    className="detail-link"
                    onClick={(e) => {
                      e.stopPropagation();
                      setSelectedReq({ ...r, isMine: mine });
                    }}
                  >
                    Xem chi tiết
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      <SupportRequestDetailModal
        request={selectedReq}
        currentUser={currentUser}
        onClose={() => setSelectedReq(null)}
        onViewMap={handleOpenMap}
        onUpdateStatus={handleUpdateStatus}
        getStatusLabel={getStatusLabel}
        getRequestTypeLabel={getRequestTypeLabel}
      />
    </div>
  );
};

export default RequestList;
